public static async Task InitializeAsync(WebApplication web)
    {
        await DB.InitAsync("SearchService",
                MongoClientSettings.
                FromConnectionString(web.Configuration.GetConnectionString("DefaultConnection")));

        await DB.Index<Item>()
            .Key(i => i.Make, KeyType.Text)
            .Key(i => i.Model, KeyType.Text)
            .Key(i => i.Color, KeyType.Text)
            .Key(i => i.Seller, KeyType.Text)
            .CreateAsync();

        var count = await DB.CountAsync<Item>();
        try
        {
            using var scope = web.Services.CreateScope();

            var httpClient = scope.ServiceProvider.GetRequiredService<IAuctionSvc>();
            var items = await httpClient.GetItemForSearchAsync();
            if (items.Count > 0)
            {
                await DB.SaveAsync(items);
            }

        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error counting items: {ex.Message}");
        }



    }

public async Task<string> GetLastUpdateTimeAsync()
    {
        var lastUpdate = await DB.Find<Item, string>()
        .Sort(x => x.Descending(x => x.UpdatedAt))
        .Project(x => x.UpdatedAt.ToString())
        .ExecuteFirstAsync();
        return lastUpdate;
    }

public async Task<ResponseDTO<List<Item>>> SearchAsync(RequestDTO requestDTO)
    {
        var query = DB.PagedSearch<Item, Item>();
        if (!string.IsNullOrEmpty(requestDTO.SearchQuery))
        {
            query.Match(Search.Full, requestDTO.SearchQuery).SortByTextScore();
        }
        if (!string.IsNullOrEmpty(requestDTO.SortBy))
        {
            try
            {
                query = requestDTO.SortDirection?.ToLower() == "desc"
               ? query.Sort(x => x.Descending(requestDTO.SortBy))
               : query.Sort(x => x.Ascending(requestDTO.SortBy));
            }
            catch (Exception ex)
            {
                throw new BadRequestException($"Invalid sort field: {requestDTO.SortBy}");
            }

        }
        else if (string.IsNullOrEmpty(requestDTO.SearchQuery))
        {
            query.Sort(x => x.Ascending(a => a.Make));
        }

        query.PageNumber(requestDTO.PageNumber ?? 1);
        query.PageSize(requestDTO.PageSize ?? 10);

        var result = await query.ExecuteAsync();

        return new ResponseDTO<List<Item>>
        {
            Data = result.Results.ToList(),
            TotalCount = (int)result.TotalCount,
            PageCount = result.PageCount
        };
    }

public void Configure(EntityTypeBuilder<Auction> builder)
    {
        builder.HasKey(a => a.Id);
        builder.Property(a => a.ReservePrice).IsRequired();
        builder.Property(a => a.Seller).IsRequired();
        builder.HasOne(a => a.Item)
            .WithOne(i => i.Auction)
            .HasForeignKey<Item>(i => i.AuctionId)
            .OnDelete(DeleteBehavior.Cascade);
    }

public static async Task Initialize(WebApplication webApplication)
    {
        using var scope = webApplication.Services.CreateScope();

        var serviceProvider = scope.ServiceProvider;
        try
        {
            var context = serviceProvider.GetRequiredService<AuctionDBContext>();
            var auctionSeeder = serviceProvider.GetRequiredService<IAuctionSeedData>();
            await context.Database.MigrateAsync();

            if (await context.Auctions.AnyAsync())
            {
                Console.WriteLine("Database already seeded");
                return;
            }

            await auctionSeeder.SeedAuctionsAsync();
            Console.WriteLine("Database seeded successfully!");

        }
        catch (Exception ex)
        {
            Console.WriteLine($"---> Lỗi cụ thể: {ex.Message}");
            Console.WriteLine($"An error occurred seeding the DB: {ex.Message}");
        }

    }

public async Task<IEnumerable<Auction>> GetAuctionsWithItemsAsync(AuctionRequestDTO requestDTO)
    {
        if (requestDTO == null)
            return await _auctionDBContext.Auctions.Include(a => a.Item).OrderBy(x => x.Item.Make).ToListAsync();

        var query = _auctionDBContext.Auctions.Include(a => a.Item).OrderBy(x => x.Item.Make).AsQueryable();
        query = query.Where(a => a.Item.Make.Contains(requestDTO.SearchQuery ?? string.Empty) &&
                                 a.Item.Model.Contains(requestDTO.SearchQuery ?? string.Empty) &&
                                a.UpdatedAt.CompareTo(DateTime.Parse(requestDTO.DateTime ?? DateTime.MinValue.ToString())) > 0);
        return await query.ToListAsync();
    }

